import React, { useState, useEffect } from "react";
import api from './api';

export default function Profile() {
  const [userProfile, setUserProfile] = useState(null);
  const [userPosts, setUserPosts] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState("");
  const [editBio, setEditBio] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [commentInput, setCommentInput] = useState({});
  const [expandedComments, setExpandedComments] = useState({});

  // Fetch user profile on component mount
  useEffect(() => {
    api.fetchProfile().then(data => {
      if (data && data.user) {
        setUser(data.user);
        setEditedAvatar(data.user.avatar_url || '');
        setEditedBio(data.user.bio || '');
      } else {
        setError('Không thể tải thông tin profile');
      }
    }).catch(err => { console.error('Error fetching profile:', err); setError('Lỗi kết nối'); }).finally(() => setLoading(false));
  }, []);

  const handleSaveProfile = async () => {
    setSaving(true);
    setError('');

    try {
      const data = await api.updateProfile({ avatar_url: editedAvatar, bio: editedBio });
      if (data && data.user) {
        setUser(data.user);
        setIsEditing(false);
      } else {
        setError(data.message || 'Lỗi cập nhật profile');
      }
    } catch (err) {
      console.error('Error updating profile:', err);
      setError('Lỗi kết nối');
    } finally {
      setSaving(false);
    }
  };

  const handleAvatarChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditedAvatar(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddPost = () => {
    if (!postContent.trim()) return;
    setPosts([{ text: postContent, time: new Date().toLocaleString() }, ...posts]);
    setPostContent("");
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px]">
        <div className="text-center">Đang tải...</div>
      </div>
    );
  }

  if (error && !user) {
    return (
      <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px]">
        <div className="text-center text-red-500">{error}</div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px]">
      <div className="flex flex-col items-center gap-8 w-full max-w-[1060px]">

        {/* --- Thông tin người dùng --- */}
        <div className="bg-[#A2D3FF] w-full p-6 rounded-2xl shadow-lg">
          <div className="flex flex-col items-center bg-[#F7FFFF] p-8 rounded-2xl relative overflow-hidden">
            <div className="flex flex-col items-center z-10">
              <span className="text-black text-3xl font-semibold mb-3">
                {user ? user.display_name || user.username : 'Loading...'}
              </span>
              <div className="flex items-center gap-5">
                {isEditing ? (
                  <div className="flex flex-col items-center">
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleAvatarChange}
                      className="mb-2"
                    />
                    {editedAvatar && (
                      <img
                        src={editedAvatar}
                        alt="avatar preview"
                        className="w-[80px] h-[75px] rounded-full object-cover"
                      />
                    )}
                  </div>
                ) : (
                  <img
                    src={user?.avatar_url || "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/tb3lhluz_expires_30_days.png"}
                    alt="avatar"
                    className="w-[80px] h-[75px] rounded-full object-cover"
                  />
                )}
                <div className="flex flex-col items-center">
                  {isEditing ? (
                    <textarea
                      value={editedBio}
                      onChange={(e) => setEditedBio(e.target.value)}
                      placeholder="Nhập bio của bạn..."
                      className="text-black text-sm mt-2 w-full p-2 border rounded"
                      rows="2"
                      maxLength="500"
                    />
                  ) : (
                    <span className="text-black text-sm mt-2">
                      {user?.bio || "Chưa có bio"}
                    </span>
                  )}
                </div>
              </div>
              {error && <div className="text-red-500 text-sm mt-2">{error}</div>}
              <div className="flex gap-2 mt-4">
                {isEditing ? (
                  <>
                    <button
                      onClick={handleSaveProfile}
                      disabled={saving}
                      className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg transition-all disabled:opacity-50"
                    >
                      {saving ? 'Đang lưu...' : 'Lưu'}
                    </button>
                    <button
                      onClick={() => {
                        setIsEditing(false);
                        setEditedAvatar(user?.avatar_url || '');
                        setEditedBio(user?.bio || '');
                        setError('');
                      }}
                      className="bg-gray-500 hover:bg-gray-600 text-white px-4 py-2 rounded-lg transition-all"
                    >
                      Hủy
                    </button>
                  </>
                ) : (
                  <button
                    onClick={() => setIsEditing(true)}
                    className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg transition-all"
                  >
                    Chỉnh sửa profile
                  </button>
                )}
              </div>
            </div>

            {/* Hình nền trang trí */}
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ths2znj7_expires_30_days.png"
              alt="decoration"
              className="absolute top-[10px] bottom-0 left-4 w-[180px] h-[160px] opacity-80"
            />
          </div>
        </div>

        {/* --- Thông tin chi tiết (3 ô hàng đầu + 3 select hàng 2) --- */}
        <div className="bg-[#A2D3FF] w-full p-6 rounded-2xl shadow-lg">
          {/* Hàng đầu */}
          <div className="flex justify-center gap-6 mb-4">
            <div className="flex flex-col items-center bg-[#FFDEF8] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Học vấn</span>
              
            </div>
            <div className="flex flex-col items-center bg-[#FFE9FA] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Những điều về tuii</span>
            </div>
            <div className="flex flex-col items-center bg-[#C6E1FF] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">#hashtag</span>
            </div>
          </div>

          {/* Hàng thứ hai có danh sách chọn */}
          <div className="flex justify-center gap-6">
            {/* Khoa */}
            <div className="flex flex-col items-center bg-[#C6E1FF] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Khoa</span>
              <select
                defaultValue="CNTT"
                className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-300"
              >
                <option value="CNTT">Công nghệ thông tin</option>
                <option value="QTKD">Quản trị kinh doanh</option>
                <option value="NNA">Ngôn ngữ Anh</option>
                <option value="NNA">Điện-điện tử</option>
                <option value="NNA">Xây dựng</option>
                <option value="KT">Khai thác hàng không</option>
                <option value="KT">Kinh tế hàng không</option>
                <option value="DL">Du lịch</option>
              </select>
            </div>

            {/* Nơi ở */}
            <div className="flex flex-col items-center bg-[#FFDEF8] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Nơi ở</span>
              <select
                defaultValue="HCM"
                className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-pink-300"
              >
                <option value="HCM">TP. Hồ Chí Minh</option>
                <option value="HN">Hà Nội</option>
                <option value="DN">Đà Nẵng</option>
                <option value="CT">Cần Thơ</option>
                <option value="BD">Bình Dương</option>
                <option value="AG">An Giang</option>
                <option value="BN">Bắc Ninh</option>
                <option value="CM">Cà Mau</option>
                <option value="CB">Cao Bằng</option>
                <option value="CT">Cần Thơ</option>
                <option value="DL">Đắk Lắk</option>
                <option value="DB">Điện Biên</option>
                <option value="DN">Đồng Nai</option>
                <option value="DT">Đồng Tháp</option>
                <option value="GL">Gia Lai</option>
                <option value="H">Hà Tĩnh</option>
                <option value="HP">Hải Phòng</option>
                <option value="H">Hà Nội</option>
                <option value="H">Hải Dương</option>
                <option value="H">Hòa Bình</option>
                <option value="H">Hậu Giang</option>
                <option value="H">Hưng Yên</option>
                <option value="H">Hà Nam</option>
                <option value="H">Hải Phòng</option>
                <option value="H">Hà Giang</option>
